INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (1146, 'موسلمانێ دورست كیە؟ و مشەختێ دورست كیە؟', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ : «المُسْلِمُ مَنْ سَلِمَ المُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ، وَالمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى الله عَنْهُ».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان ئه‌وه‌ یێ موسلمان ژ ئه‌زمانێ وى و ده‌ستێ وى دپارستى بن، و مشه‌خت ئه‌وه‌ یێ پشت بده‌ته‌ وى یێ یێ خودێ نه‌هى ژێ كرى.', NULL, true),
  (1156, 'سالۆخەتێن موسلمانێ دورست', 'عَنِ عَبْدِ الله بْنِ عُمَرَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «المُسْلِمُ أَخُو المُسْلِمِ لاَ يَظْلِمُهُ، وَلاَ يُسْلِمُهُ، وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ الله فِي حَاجَتِهِ، وَمَنْ فَرَّجَ عَنْ مُسْلِمٍ كُرْبَةً فَرَّجَ الله عَنْهُ كُرْبَةً مِنْ كُرُبَاتِ يَوْمِ الْقِيَامَةِ، وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ الله يَوْمَ الْقِيَامَةِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان برایێ موسلمانییه‌ زۆردارییێ لێ ناكه‌ت، و وى ته‌سلیمى دوژمنى ناكه‌ت، و هه‌چییێ د خێرا برایێ خۆ دا بت خودێ دێ د خێرا وى دا بت، و هه‌چییێ ته‌نگاڤییه‌كێ ژ سه‌ر موسلمانه‌كى ڕاكه‌ت خودێ ته‌نگاڤییه‌كێ ژ ته‌نگاڤییێن ڕۆژا قیامه‌تێ دێ ژ سه‌ر وى ڕاكه‌ت، و هه‌چییێ موسلمانه‌كى ستاره‌ بكه‌ت ڕۆژا قیامه‌تێ خودێ دێ وى ستاره‌ كه‌ت.', NULL, true),
  (1166, 'حەفت ئەمر و حەفت نەهى', 'قَالَ الْبَرَاءُ بْنُ عَازِبٍ رضي الله عنه : أَمَرَنَا النَّبِيُّﷺ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ، أَمَرَنَا بِعِيَادَةِ المَرِيضِ، وَاتِّبَاعِ الْجِنَازَةِ، وَتَشْمِيتِ الْعَاطِسِ، وَإِبْرَارِ الْقَسَمِ، وَنَصْرِ المَظْلُومِ، وَإِفْشَاءِ السَّلاَمِ، وَإِجَابَةِ الدَّاعِي، وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ، وَعَنْ آنِيَةِ الْفِضَّةِ، وَعَنِ المَيَاثِرِ، وَالْقَسِّيَّةِ، وَالإِسْتَبْرَقِ، وَالدِّيبَاجِ.', 'به‌ررائێ كوڕێ عازبى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- فه‌رمان ب حه‌فت تشتان ل مه‌ كر، و ئه‌م ژ حه‌فت تشتان داینه‌ پاش، وى فه‌رمان ب سه‌ره‌دانا نه‌خۆشان ل مه‌ كر و دویكه‌فتنا جه‌نازه‌یان، و به‌رسڤدانا وى یێ دبێنژت، و نه‌شكاندنا سویندا وى یێ مرۆڤى دده‌ته‌ سویندێ، و پشته‌ڤانییا وى یێ سته‌م لێ دئێته‌كرن، و به‌لاڤكرنا سلاڤێ، و چوونا د به‌رسڤا وى یێ مرۆڤى ڤه‌خوینت، و وى ئه‌م ل به‌رخۆكرنا گوستیركێن زێڕى داینه‌ پاش، و خوارنا د ئامانێن زیڤى دا، و جلێن ده‌واران ئه‌وێن ژ ئاڤرمیشى دئێنه‌ چێكرن، و كراسێن ئاڤرمیشى، و كراسێن ئیسته‌بره‌ق و دیباجى (و ئه‌و ژى دو ڕه‌نگێن ئاڤرمیشینه‌).', NULL, true),
  (1176, 'خودان باوەر خودان باوەرى دگرت', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّ المُؤْمِنَ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا» وَشَبَّكَ أَصَابِعَهُ.', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خودان باوه‌ر بۆ خودان باوه‌رى وه‌كى ئاڤاهییه‌ هنده‌ك هنده‌كێ دگرت. و وى تبلێن خۆ كرنه‌ د ناڤێك ڕا.', NULL, true),
  (1186, 'مەتەلا خودان باوەران', 'عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَثَلُ المُؤْمِنِينَ فِي تَوَادِّهِمْ، وَتَرَاحُمِهِمْ، وَتَعَاطُفِهِمْ، مَثَلُ الجَسَدِ إِذَا اشْتَكَى مِنْهُ عُضْوٌ تَدَاعَى لَهُ سَائِرُ الجَسَدِ بِالسَّهَرِ وَالحُمَّى».', 'نوعمانێ كوڕێ به‌شیرى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: مه‌ته‌لا خودان باوه‌ران د ڤیان و ره‌حم و دلۆڤانییا وان دا، وه‌كى مـه‌تــه‌لا لـه‌شییه‌، ئــه‌گــه‌ر ئـه‌نـدامه‌ك ژێ ئێشا له‌ش هه‌مى تاگرتى دبت و خه‌و ب چاڤان ناكه‌ڤت.', NULL, true),
  (1196, 'دو ڕەنگێن دورست یێن حەسویدییێ', 'عَنْ عَبْدِ الله بْنِ مَسْعُودٍ رضي الله عنه يَقُولُ: قَالَ رَسُولُ اللهﷺ : «لاَ حَسَدَ إِلاَّ فِي اثْنَتَيْنِ: رَجُلٌ آتَاهُ الله مَالاً، فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الحَقِّ، وَرَجُلٌ آتَاهُ الله حِكْمَةً، فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا».', 'عـه‌بـدللاهـێ كــوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: حه‌سویدى چێ نابت، یا دو مرۆڤان تێ نه‌بت: زه‌لامه‌كى خودێ ماله‌كێ دایێ ڤێجا ئه‌و وى د حه‌قییێ دا خه‌رج دكه‌ت، و زه‌لامه‌كى خودێ زانینا (قورئانێ) یا دایێ ڤێجا ئه‌و حوكمى پێ دكه‌ت، و وێ نیشا خه‌لكى دده‌ت.', NULL, true),
  (1206, 'ژ سالۆخەتێن بەحەشتى و جەهنەمییان', 'عَن حَارِثَةَ بْنِ وَهْبٍ الخُزَاعِيِّ رضي الله عنه قَالَ: سَمِعْتُ النَّبِيَّﷺ يَقُولُ: «أَلَا أُخْبِرُكُمْ بِأَهْلِ الجَنَّةِ؟ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى الله لَأَبَرَّهُ، أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ؟ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ».', 'حارثه‌یێ كوڕێ وه‌هه‌بێ خوزاعى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌رێ ئه‌ز بۆ هه‌وه‌ به‌حسێ به‌حه‌شتییان نه‌كه‌م كینه‌؟ هه‌ر لاوه‌زه‌كێ خه‌لك وى لاواز دبینن، ئه‌گه‌ر ئه‌و خودێ بده‌ته‌ سویندێ خودێ سویندا وى دێ ب جهـ ئینت، و ئه‌ز بۆ هه‌وه‌ به‌حسێ جه‌هنه‌مییان نه‌كه‌م؟ هه‌ر كه‌سێ زڤڕ و ڕه‌ق و خۆ مه‌زن دكه‌ت.', NULL, true),
  (1216, 'دا كو نعمەتا خودێ كێم نەكەى', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْظُرُوا إِلَى مَنْ أَسْفَلَ مِنْكُمْ، وَلاَ تَنْظُرُوا إِلَى مَنْ هُوَ فَوْقَكُمْ، فَهُوَ أَجْدَرُ أَنْ لاَ تَزْدَرُوا نِعْمَةَ الله».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: به‌رێ خۆ بده‌نه‌ یێن د بن خۆ دا، و به‌رێ خۆ نه‌ده‌نه‌ یێن د سه‌ر خۆ دا، ئه‌و هه‌ژیتره‌ كو هوین نعمه‌تا خودێ كێم نه‌كه‌ن.', NULL, true),
  (1226, 'دو گونەهێن مرۆڤ د قەبرى دا پێ دئێته عەزابدان', 'عَنْ ابْنِ عَبَّاسٍ رضي الله عنه قَالَ مَرَّ النَّبِيُّﷺ بِقَبْرَيْنِ فَقَالَ: «إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ، أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ الْبَوْلِ، وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ».', 'ئبن عه‌بباس -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- د به‌ر دو قه‌بران ڕا بۆرى، و گۆت: ئه‌و هه‌ردو یێن دئێنه‌ عه‌زابدان، و ئه‌و نه‌ ژ به‌ر تشته‌كێ مه‌زن دئێنه‌ عه‌زابدان، ئێك ژ وان خۆ ژ ده‌سنڤێژا زراڤ نه‌دپاراست، و یێ دى قه‌سه‌ ڤه‌دگوهازتن.', NULL, true),
  (1236, 'قەسەڤەگوهێز ناچته بەحەشتێ', 'قَالَ حُذَيْفَةُ رضي الله عنه : سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «لاَ يَدْخُلُ الجَنَّةَ نَمَّامٌ».', 'حوذه‌یفه‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: قه‌سه‌ڤه‌گوهێز ناچته‌ به‌حه‌شتێ.
به‌یعا صه‌حابییان بۆ پێغه‌مبه‌رى ل سه‌ر چ بوو؟', NULL, true),
  (1246, 'حوذەیفه -خودێ ژێ رازى بت- دبێژت: پێغەمبەرى -سلاڤ لێ بن- گۆت: قەسەڤەگوهێز ناچته بەحەشتێ. بەیعا صەحابییان بۆ پێغەمبەرى ل سەر چ بوو؟', 'عَنْ عُبَادَةَ بْنِ الْصامتِ رضي الله عنه قَالَ: بَايَعْنَا رَسُولَ اللهﷺ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ، وَالْمَنْشَطِ وَالمَكْرَهِ، وَعَلَى أَثَرَةٍ عَلَيْنَا، وَعَلَى أَنْ لاَ نُنَازِعَ الأَمْرَ أَهْلَهُ، إلا أنْ تَرَوا كفراً بواحاً عندكم منَ الله فيه بُرهانٌ، وَعَلَى أَنْ نَقُولَ بِالحَقِّ أَيْنَمَا كُنَّا، لاَ نَخَافُ فِي الله لَوْمَةَ لاَئِمٍ.', 'عوباده‌یێ كوڕێ صامتى -خودێ ژێ رازى بت- دبێژت: مه‌ به‌یعه‌ دا پێغه‌مبه‌رى -سلاڤ لێ بن- كو ئه‌م ل ته‌نگاڤى و فره‌هییێ و خۆشى و نه‌خۆشییێ گوهدارییێ بكه‌ین، و وى ب پێش خۆ بێخین، و كو ئه‌م هه‌ڤڕكییا مه‌زنان د كارێ وان دا نه‌كه‌ین، وه‌سا نه‌بت هوین كوفره‌كا ئاشكه‌را ببینن هه‌وه‌ ده‌لیله‌ك ژ خودێ ل سه‌ر هه‌بت، و كو ئه‌م حه‌قییێ بێژین ل چى جهێ ئه‌م لێ بین، ئه‌م د ده‌ر حه‌قا خودێ دا ژ لۆمه‌یا كۆمكه‌رى نه‌ترسین.', NULL, true),
  (1256, NULL, 'عَن عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: بَايَعْتُ رَسُولَ اللهﷺ فِي رَهْطٍ فَقَالَ: «أُبَايِعُكُمْ عَلَى أَنْ لاَ تُشْرِكُوا بِالله شَيْئًا، وَلاَ تَسْرِقُوا، وَلاَ تَقْتُلُوا أَوْلاَدَكُمْ، وَلاَ تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ، وَلاَ تَعْصُونِي فِي مَعْرُوفٍ. فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى الله، وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَأُخِذَ بِهِ فِي الدُّنْيَا فَهْوَ كَفَّارَةٌ لَهُ وَطَهُورٌ، وَمَنْ سَتَرَهُ الله فَذَلِكَ إِلَى الله إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ».', 'عوباده‌یێ كوڕێ صامتى -خودێ ژێ رازى بت- دبێژت: من د ناڤ كۆمه‌كێ دا به‌یعه‌ دا پێغه‌مبه‌رى -سلاڤ لێ بن- وى گۆت: ئه‌ز دێ به‌یعێ ده‌مه‌ هه‌وه‌ كو هوین چو شریكان بۆ خودێ چێ نه‌كه‌ن، و دزییێ نه‌كه‌ن، و زنایێ نه‌كه‌ن، و زارۆكێن خۆ نه‌كوژن، و چـو بـێـبـه‌خییان ل به‌ر ده‌ست و پییێن خۆ نه‌كه‌ن، و هوین د كارێ قه‌نج دا بێ ئه‌مرییا من نه‌كه‌ن. ڤێجا هه‌چییێ ژ هه‌وه‌ ئه‌ڤ چه‌نده‌ ب جهـ ئینا خێرا وى ل سه‌ر خودێیه‌، و هه‌چییێ تشته‌ك ژ وان كر، و د دنیایێ دا ئه‌و پێ هاته‌گرتن ئه‌و دێ بته‌ پاقژكرن و ژێبرن بۆ گونه‌ها وى، و هه‌چییێ خودێ وى ستاره‌ بكه‌ت، ئه‌و ل سه‌ر به‌ختێ خودێیه‌، ئه‌گه‌ر وى بڤێت ئه‌و دێ وى عه‌زاب ده‌ت، و ئه‌گه‌ر بڤێت دێ گونه‌ها وى ژێ به‌ت.', NULL, true),
  (1266, 'ئەو كارێن بۆ مرۆڤى خێر', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «كُلُّ سُلَامَى مِنْ النَّاسِ عَلَيْهِ صَدَقَةٌ، كُلَّ يَوْمٍ تَطْلُعُ فِيهِ الشَّمْسُ يَعْدِلُ بَيْنَ الِاثْنَيْنِ صَدَقَةٌ، وَيُعِينُ الرَّجُلَ عَلَى دَابَّتِهِ فَيَحْمِلُ عَلَيْهَا أَوْ يَرْفَعُ عَلَيْهَا مَتَاعَهُ صَدَقَةٌ، وَالْكَلِمَةُ الطَّيِّبَةُ صَدَقَةٌ، وَكُلُّ خُطْوَةٍ يَخْطُوهَا إِلَى الصَّلَاةِ صَـدَقَـةٌ، وَيُمِيطُ الْأَذَى عَـنْ الطَّرِيقِ صَدَقَةٌ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر گه‌هه‌كا د له‌شێ مرۆڤان دا هه‌ى خێره‌ك ل سه‌ر هه‌یه‌، هه‌ر ڕۆژه‌كا دهه‌لێت و ئه‌و دادییێ د ناڤبه‌را دویان دا دكه‌ت خێره‌كه‌، و هاریكارییا زه‌لامه‌كى ل سه‌ر ده‌وارا وى دكه‌ت وى لێ بار دكه‌ت یان بارێ وى هل دده‌ته‌ سه‌ر خێره‌كه‌، و گۆتنا باش خێره‌كه‌، و هه‌ر پێگاڤه‌كا ئه‌و بۆ نڤێژێ دهاڤێت خێره‌كه‌، و ڕاكرنا نه‌خۆشییێ ژ ڕێكێ خێره‌كه‌.', NULL, true),
  (1276, 'مافێ ڕێكێ', 'عَنْ أَبِي سَعِيدٍ الخُدْرِيِّ رضي الله عنه عَنْ النَّبِيِّﷺ قَالَ: «إِيَّاكُمْ وَالجُلُوسَ عَلَى الطُّرُقَاتِ» فَقَالُوا: مَا لَنَا بُدٌّ إِنَّمَا هِيَ مَجَالِسُنَا نَتَحَدَّثُ فِيهَا، قَالَ: «فَإِذَا أَبَيْتُمْ إِلَّا المَجَالِسَ فَأَعْطُوا الطَّرِيقَ حَقَّهَا» قَالُوا: وَمَا حَقُّ الطَّرِيقِ؟ قَالَ: «غَضُّ الْبَصَرِ، وَكَفُّ الْأَذَى، وَرَدُّ السَّلَامِ، وَأَمْرٌ بِالمَعْرُوفِ، وَنَهْيٌ عَنْ المُنْكَرِ».', 'ئه‌بوو سه‌عیدێ خودرى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هشیارى ڕوینشتنا ل سه‌ر ڕێكان بن، گۆتن: مه‌ ژ بلى وان چو جهێن دى نینن، ئه‌و دیوانخانه‌یێن مه‌نه‌ ئه‌م سوحبه‌تێن خۆ لێ دكه‌ین، وى گۆت: ئه‌گه‌ر هوین هه‌ر دێ لێ ڕوینن، هوین مافێ ڕێكێ بده‌نێ، گۆتن: مافێ ڕێكێ چییه‌؟ وى گۆت: گرتنا چاڤییه‌ و نه‌گه‌هاندنا نه‌خۆشییێیه‌، و زڤڕاندنا سلاڤێیه‌، و فه‌رمانا ب باشییێیه‌، و پاشڤه‌برنا ژ خرابییێیه‌.', NULL, true),
  (1286, 'كیژ موسلمانەتى باشترە؟', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه أَنَّ رَجُلًا سَأَلَ النَّبِيَّﷺ : أَيُّ الْإِسْلَامِ خَيْرٌ؟ قَالَ: «تُطْعِمُ الطَّعَامَ، وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: زه‌لامه‌كى پسیار ژ پێغه‌مبه‌رى -سلاڤ لێ بن- كر: كیژ موسلمانه‌تى چێتره‌؟ وى گۆت: كو تو خوارنێ بده‌ى، و سـلاڤـێ بده‌یه‌ وى یێ تو دنیاسى، و وى یێ تو نه‌نیاسى ژى.', NULL, true),
  (1296, 'ژ پێتڤییێن باوەرییا ب خودێ و ڕۆژا دووماهییێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ النَّبِيِّﷺ قَالَ: «مَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ، وَمَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيَصِلْ رَحِمَهُ، وَمَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌بت بلا قه‌درێ مێڤانی خۆ بـگـرت، و هــه‌چــیــیـێ بـاوه‌رى ب خــودی و ڕۆژا دوومــاهــیــیــێ هه‌بت بلا یێ ب مرۆڤاینى بت، و هه‌چییێ باوه‌رى ب خودی و ڕۆژا دووماهییێ هه‌بت بلا خێرێ بێژت یان خۆ بێ ده‌نگ بكه‌ت.', NULL, true),
  (1306, 'سوننەتا دەستویردانێ', 'عَنْ أَبِي مَسْعُودٍ الأَنْصَارِيِّ رضي الله عنه قَالَ: دعَا رَجُلٌ النَّبيَّﷺ لِطَعامٍ صَنَعَهُ خامِسَ خمسَةٍ، وأتْبَعَهُمْ رجلٌ، فلما بَلَغَ البابَ، قال النَّبِيُّﷺ : «إِنَّ هَذَا اتَّبَعَنَا، فَإِنْ شِئْتَ أَنْ تَأْذَنَ لَهُ، وَإِنْ شِئْتَ رَجَعَ» قَالَ: لاَ، بَلْ آذَنُ لَهُ يَا رَسُولَ الله.', 'ئه‌بوو مه‌سعوودێ ئه‌نصارى -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌كى پێغه‌مبه‌ر -سلاڤ لێ بن- د گه‌ل چــار كــه‌ســان ڤه‌خوانده‌ مالا خۆ، و زه‌لامه‌ك ب دویڤ وان كه‌فت، ده‌مێ ئه‌و گه‌هشتییه‌ به‌ر ده‌رگه‌هى، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌ڤه‌ یێ ب دویڤ مه‌ كه‌فتى، ئه‌گه‌ر تو حه‌ز بكه‌ى ده‌ستویرییێ بدێ، و ئه‌گه‌ر تو حه‌ز بكه‌ى ئه‌و دێ زڤڕت. وى گۆت: نه‌، ئه‌ز دێ ده‌ستویرییێ ده‌مێ ئه‌ى پێغه‌مبه‌رێ خودێ.', NULL, true),
  (1316, NULL, 'عن أَبـي مُـوسَـى الأَشْـعَــرِيِّ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «الاِسْتِئْذَانُ ثَلاَثٌ، فَإِنْ أُذِنَ لَكَ وَإِلاَّ فَارْجِعْ».', 'ئــه‌بــوو مــووســایــێ ئـه‌شـعـه‌رى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خواستنا ده‌ستویرییێ سێ جارانه‌، ڤێجا ئه‌گه‌ر ده‌ستویرى بۆ ته‌ هاته‌دان هه‌ڕه‌، ئه‌گه‌ر نه‌ بزڤڕه‌ڤه‌.', NULL, true),
  (1326, 'ئەوێ جیرانێ وى یێ ژێ ئەمین نەبت', 'عَنْ أَبِي هريرة رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «وَالله لَا يُؤْمِنُ، وَالله لَا يُؤْمِنُ، وَالله لَا يُؤْمِنُ» قِيلَ: وَمَنْ يَا رَسُولَ الله؟ قَالَ: «الَّذِي لَا يَأْمَنُ جَارُهُ بَوَايِقَهُ».', 'ئــه‌بــوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ب خودێ ئه‌و باوه‌رییێ نائینت، ب خودێ ئه‌و باوه‌رییێ نائینت، ب خودێ ئه‌و باوه‌رییێ نائینت، گۆتن: و ئه‌و كییه‌ ئه‌ى پێغه‌مبه‌رێ خودێ؟ گۆت: ئه‌وێ جیرانێ وى یێ ژ خرابییێن وى ئه‌مین نه‌بت.', NULL, true),
  (1336, 'ئەوێ بێ دەستویرى بەرێ خۆ بدەته مالەكێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «مَنِ اطَّلَعَ فِي بَيْتِ قَوْمٍ بِغَيْرِ إِذْنِهِمْ، فَقَدْ حَلَّ لَهُمْ أَنْ يَفْقَؤُوا عَيْنَهُ».', 'ئــه‌بــوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ به‌رێ خۆ بده‌ته‌ ماله‌كێ بێى ده‌ستویرییا وان، بۆ وان هه‌یه‌ ئه‌و چاڤێن وى بیننه‌ ده‌ر.', NULL, true);